(function(){
  var $=function(id){return document.getElementById(id);};
  var fmt=function(n){return '$'+Math.round(n).toLocaleString('en-US');};
  var pc=function(n){return (Math.round(n*10)/10)+'%';};
  function calc(){
    var inc=+$('dtiIncome').value||0, hou=+$('dtiHousing').value||0, debt=+$('dtiDebts').value||0;
    var front= inc>0 ? hou/inc*100 : 0;
    var back= inc>0 ? (hou+debt)/inc*100 : 0;
    $('dtiBack').innerHTML=(inc>0?pc(back):'—')+'<small>back-end</small>';
    $('dtiFront').textContent= inc>0?pc(front):'—';
    $('dtiObl').textContent= fmt(hou+debt)+'/mo';
    var status;
    if(inc<=0){status='Enter your income';}
    else if(back<=43){status='✓ Within typical FHA range (≤43%)';}
    else if(back<=50){status='Above standard — possible with compensating factors';}
    else {status='High — likely needs strong compensating factors';}
    $('dtiStatus').textContent=status;
  }
  ['dtiIncome','dtiHousing','dtiDebts'].forEach(function(id){$(id).addEventListener('input',calc);});
  calc();
})();
